# Minimal education agent orchestrator using the Anthropic SDK

import anthropic
from dataclasses import dataclass, field

client = anthropic.Anthropic()

@dataclass
class LearnerModel:
    learner_id: str
    mastery: dict[str, float] = field(default_factory=dict)   # concept_id -> [0, 1]
    history: list[dict] = field(default_factory=list)

    def get_mastery(self, concept_id: str) -> float:
        return self.mastery.get(concept_id, 0.0)

    def update_mastery(self, concept_id: str, correct: bool, learn_rate: float = 0.2):
        p = self.get_mastery(concept_id)
        if correct:
            self.mastery[concept_id] = p + (1 - p) * learn_rate
        else:
            self.mastery[concept_id] = p * (1 - learn_rate * 0.5)

CURRICULUM = {
    "python-variables": {
        "title": "Variables and Assignment",
        "explanation": "A variable is a named binding to a value. Use = to assign: x = 42.",
        "exercises": [
            {"prompt": "Write a Python statement that assigns the integer 10 to a variable named score.", "answer_key": "score = 10"},
        ],
    },
    "python-functions": {
        "title": "Defining Functions",
        "explanation": "Use def to create a function. The body is indented.",
        "exercises": [
            {"prompt": "Define a function named greet that takes a name parameter and returns 'Hello, <name>'.", "answer_key": "def greet(name): return f'Hello, {name}'"},
        ],
        "prerequisites": ["python-variables"],
    },
}

def orchestrate_turn(learner: LearnerModel, concept_id: str, student_input: str) -> str:
    concept = CURRICULUM[concept_id]
    mastery = learner.get_mastery(concept_id)

    # Choose instructional action based on mastery level
    if mastery < 0.3:
        action = "explain"
    elif mastery < 0.7:
        action = "quiz"
    else:
        action = "advance"

    if action == "explain":
        system = (
            "You are a patient Python tutor. Explain the concept clearly with a concrete example. "
            "End with one short check question."
        )
        user = f"Concept: {concept['title']}\n\nKnowledge: {concept['explanation']}\n\nStudent said: {student_input}"
    elif action == "quiz":
        exercise = concept["exercises"][0]
        system = (
            "You are a strict but encouraging Python tutor. "
            "Evaluate whether the student's answer is correct. "
            "If correct, say CORRECT and explain why. "
            "If incorrect, identify the specific error and give a targeted hint — do NOT give the full answer."
        )
        user = f"Exercise: {exercise['prompt']}\nExpected: {exercise['answer_key']}\nStudent answer: {student_input}"
    else:
        return f"Great work on {concept['title']}! You're ready to move on."

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        system=system,
        messages=[{"role": "user", "content": user}],
    )
    agent_reply = response.content[0].text

    # Update mastery based on keywords in reply
    correct = "CORRECT" in agent_reply.upper()
    learner.update_mastery(concept_id, correct)
    learner.history.append({"concept": concept_id, "action": action, "correct": correct})

    return agent_reply

# Example session
learner = LearnerModel(learner_id="student-001")
reply = orchestrate_turn(learner, "python-variables", "I'm not sure what a variable is")
print(reply)
print("Mastery after turn:", learner.get_mastery("python-variables"))
